#include <stdio.h>
#define MOD 1000000007
long long f[100];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        if (N == 1) {
            printf("2\n");
        } else if (N == 2) {
            printf("4\n");
        } else {
            long long a = 2, b = 4;
            for (int i = 3; i <= N; i++) {
                long long temp = (a + b) % MOD;
                a = b;
                b = temp;
            }
            printf("%lld\n", b);
        }
    }
    return 0;
}

